#include <iostream>
using namespace std;
template<typename T>
class Stack {
    T data[10];
    int top = 0;
public:
    void push(T v) { data[top++] = v; }
    T pop() { return data[--top]; }
};
int main() {
    Stack<int> s;
    s.push(10);
    s.push(20);
    s.push(30);
    cout << s.pop() << "\n";
    cout << s.pop() << "\n";
    return 0;
}

